import{_ as o,c as t,o as e,a3 as r}from"./chunks/framework.BDUgfJP_.js";const m=JSON.parse('{"title":"伺服器連線","description":"","frontmatter":{},"headers":[],"relativePath":"mc_server/join.md","filePath":"mc_server/join.md","lastUpdated":null}'),a={name:"mc_server/join.md"},n=r('<h1 id="伺服器連線" tabindex="-1">伺服器連線 <a class="header-anchor" href="#伺服器連線" aria-label="Permalink to &quot;伺服器連線&quot;">​</a></h1><p>要進行伺服器連線，首先需要確認<strong>伺服器</strong>和<strong>你的電腦</strong>所連接的網路是否<strong>相同</strong>。 要檢查網路IP，<strong>Windows</strong>請開啟<strong>命令提示字元</strong>或<strong>PowerShell</strong>，MacOS請開啟<strong>terminal(終端機)</strong>，並輸入<code>ipconfig</code>，尋找<code>IPv4</code>的選項，確認後方的網路IP是否相同。</p><h2 id="伺服器與遊玩的電腦連接同個網路" tabindex="-1">伺服器與遊玩的電腦連接同個網路 <a class="header-anchor" href="#伺服器與遊玩的電腦連接同個網路" aria-label="Permalink to &quot;伺服器與遊玩的電腦連接同個網路&quot;">​</a></h2><p>開啟Minecraft。 選擇<strong>多人遊戲</strong>之後，在伺服器IP的位置輸入<code>localhost</code>或是剛才輸入<code>ipconfig</code>之後查看的網路IP後即可連線。</p><h2 id="伺服器與遊玩的電腦連接不同網路" tabindex="-1">伺服器與遊玩的電腦連接不同網路 <a class="header-anchor" href="#伺服器與遊玩的電腦連接不同網路" aria-label="Permalink to &quot;伺服器與遊玩的電腦連接不同網路&quot;">​</a></h2><p>如果伺服器與遊玩的電腦連接不同網路，那麼有以下幾種不同的連線方式:</p><ul><li>進行<strong>port forwarding</strong>(比較麻煩，需要進行路由器設定)</li><li>使用VPN連線(使用<strong>Radmin VPN</strong>進行連線)</li></ul>',7),s=[n];function i(c,d,l,_,g,h){return e(),t("div",null,s)}const f=o(a,[["render",i]]);export{m as __pageData,f as default};
